(function(){"use strict";function initAddressPicker(){var sel=document.getElementById("saved-address-picker");if(!sel)return;var fieldMap={name:"name",phone:"phone",address:"address",city:"city",zip:"zip"};function fill(opt){if(!opt||!opt.value)return;var f=document.querySelector("form.panel");if(!f)return;for(var k in fieldMap){var v=opt.dataset[k];var el=f.querySelector('[name="'+fieldMap[k]+'"]');if(el&&v!=null)el.value=v}}sel.addEventListener("change",function(){fill(sel.options[sel.selectedIndex])});if(sel.value)fill(sel.options[sel.selectedIndex])}function initInvoiceToggle(){var radios=document.querySelectorAll('[data-toggle="invoice-fields"]');var box=document.getElementById("company-fields");if(!box||!radios.length)return;function sync(){var v=document.querySelector('[data-toggle="invoice-fields"]:checked');box.style.display=v&&v.value==="company"?"grid":"none"}radios.forEach(function(r){r.addEventListener("change",sync)})}if(document.readyState!=="loading"){initAddressPicker();initInvoiceToggle()}else{document.addEventListener("DOMContentLoaded",function(){initAddressPicker();initInvoiceToggle()})}})();